+        #[test]
+        fn selection_strategy_all_variants_roundtrip() {
+            let strategies = [
+                SelectionStrategy::Priority,
+                SelectionStrategy::Fastest,
+                SelectionStrategy::Balanced,
+                SelectionStrategy::CacheAffinity,
